sys_script_client.script:
function onLoad() {

	// 	RAJ - STRY0063655 - Show and hide Primary Assignee, Assigned Member, Subtask Primary Assignee(s) and Subtask Assigned Member(s).
	//NOTE: I tried to do this in a UI Policy, but Parent is not on the New form for a new task.  Portal pages don't apply ui policy well when fields not in the form are needed for the condition.  So, logic was moved here.

	// hide these fields  on form load always
	// they are only turned on when the u_create_multiple_subtasks is checked which, by default is off.
	g_form.setDisplay('u_subtask_assigned_member_s',false);
	g_form.setDisplay('u_subtask_primary_assignee_s',false);

	// 	RAJ - STRY0064119 - show hide the checkbox for choosing whether subtasks are created in parallel or serial
	//  this defaults to off and comes on only when multi select is on.
		g_form.setDisplay('u_create_subtasks_in_serial',false);   
}
